module regfile32bit (
    input wire clk,
    input wire rst,
    input wire we,
    input wire [1:0] rd_addr1,
    input wire [1:0] rd_addr2,
    input wire [1:0] wr_addr,
    input wire [31:0] wr_data,
    output reg [31:0] rd_data1,
    output reg [31:0] rd_data2
);

    reg [31:0] rf [3:0];

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            rf[0] <= 32'b0;
            rf[1] <= 32'b0;
            rf[2] <= 32'b0;
            rf[3] <= 32'b0;
        end else if (we) begin
            rf[wr_addr] <= wr_data;
        end
    end

    always @(*) begin
        rd_data1 = rf[rd_addr1];
        rd_data2 = rf[rd_addr2];
    end

endmodule
